let _enrichmentDbCache = null;
const _loadEnrichmentDb = async () => {
  if (!_enrichmentDbCache) {
    _enrichmentDbCache = await import("./enrichment-db");
  }
  return _enrichmentDbCache;
};
let enrichedRoutes = {}, getEnrichment = () => null, determineTier = () => null;

// Lazy-load enrichment-db on first route view
const useEnrichmentDb = () => {
  const [loaded, setLoaded] = useState(false);
  useEffect(() => {
    _loadEnrichmentDb().then(m => {
      enrichedRoutes = m.enrichedRoutes;
      getEnrichment = m.getEnrichment;
      determineTier = m.determineTier;
      setLoaded(true);
    });
  }, []);
  return loaded;
};

// Merge enriched data into routes at startup
const enrichRoute = (route) => {
  if (!route || !route.id) return route;
  const enrichData = getEnrichment(route.id);
  let out = enrichData ? { ...route, ...enrichData } : route;
  // Backend (DB-sourced) routes already carry elevation/prominence/first-ascent/best-season
  // in real columns (see lib/db.js's _dbArea embed + dbRouteToCamel) — synthesize the
  // PeakMetadataPanel shape from them instead of requiring a separate hand-seeded entry.
  // Only do this for actual peak/summit areas — a crag or wall isn't a "peak" and
  // shouldn't get a PEAK panel just because its area row happens to carry elevation data.
  const isPeakArea = out._dbArea ? out._dbArea.areaType === "peak" : ["mountaineering", "alpine", "scrambling"].includes(out.discipline);
  if (!out.peakMetadata && isPeakArea && (out._dbArea || out.fa)) {
    const a = out._dbArea || {};
    // area.region is frequently just a leftover state-name placeholder ("Washington")
    // rather than a real range/sub-area name — when so, fall back to the parent area's
    // name, which is reliably a proper range or sub-region (e.g. "Stuart-Enchantments",
    // "Cascade River / Eldorado / Forbidden") even though region wasn't backfilled.
    const ownRegion = (a.region && a.region !== "Washington") ? a.region : null;
    const parentRegion = (a.parentName && a.parentName !== "Washington") ? a.parentName : null;
    out = { ...out, peakMetadata: {
      elevation: a.elevation ?? null,
      prominence: a.prominence ?? null,
      range: ownRegion || parentRegion || null,
      geology: a.blurb || null,
      firstAscent: out.fa ? { date: null, climbers: [], notes: out.fa } : null,
    } };
  }
  if (!out.seasonalGuidance && out.bestSeason) {
    out = { ...out, seasonalGuidance: { optimalWindow: out.bestSeason } };
  }
  return out;
};

