// --- MP-accurate area-tree rules & dev validator ---
// A "crag" is simply the LEAF area that holds routes. Invariants enforced:
//  (1) every route.mountainId exists  (2) routes attach only to leaf areas
//  (3) an area holds EITHER sub-areas OR routes, never both.
const areaHasChildren=id=>MOUNTAINS.some(m=>m.parentId===id);
function auditAreaData(){const out=[];const ids=new Set(MOUNTAINS.map(m=>m.id));const routed=new Set(ROUTES.map(r=>r.mountainId));
MOUNTAINS.forEach(m=>{if(m.parentId&&!ids.has(m.parentId))out.push('area "'+m.id+'" -> missing parent "'+m.parentId+'"');if(areaHasChildren(m.id)&&routed.has(m.id))out.push('area "'+m.id+'" holds BOTH sub-areas and routes');});
ROUTES.forEach(r=>{if(!ids.has(r.mountainId))out.push('route "'+r.id+'" -> unknown area "'+r.mountainId+'"');else if(areaHasChildren(r.mountainId))out.push('route "'+r.id+'" attaches to non-leaf area "'+r.mountainId+'"');});
if(out.length)console.warn("[area-tree] "+out.length+" MP-hierarchy issue(s):\n  "+out.join("\n  "));return out;}
try{if(import.meta&&import.meta.env&&import.meta.env.DEV)auditAreaData();}catch(e){}
