function DiscBadges({route,sm}){const ds=(route&&route.disciplines&&route.disciplines.length?route.disciplines:[catOf(route)]);return <span style={{display:"inline-flex",flexWrap:"wrap",gap:4,alignItems:"center"}}>{ds.map(function(d){return <DiscBadge key={d} id={d} sm={sm}/>;})}</span>;} function TrustBadge({score,compact}){const col=score>=90?C.green:score>=70?C.blue:score>=50?C.amber:C.red;const bg=score>=90?C.greenBg:score>=70?C.blueBg:score>=50?C.amberBg:C.redBg;const lbl=score>=90?"Highly Trusted":score>=70?"Trusted":score>=50?"Building Trust":"New";return <span title="Trust score (0–100): built from ID verification, partner vouches, belay catches logged, climbs logged and certifications. Higher means more proven." style={{display:"inline-flex",verticalAlign:"middle"}}><Pill icon={<ActionIcon name="shield" size={11} color={col}/>} label={compact?`${score}`:`${score} — ${lbl}`} color={col} bg={bg} sm/></span>;}
