  useEffect(()=>{let c=false;setLoading(true);(async()=>{try{const pr=await fetch(`https://api.weather.gov/points/${lat.toFixed(4)},${lng.toFixed(4)}`);if(!pr.ok)throw new Error();const pj=await pr.json();const fr=await fetch(pj.properties.forecast);if(!fr.ok)throw new Error();const fj=await fr.json();if(!c)setData((fj.properties&&fj.properties.periods||[]).slice(0,5));}catch(e){if(!c)setErr(true);}if(!c)setLoading(false);})();return()=>{c=true;};},[lat,lng]);
