const SAFETY_ESSENTIALS={
sport:{title:"Clipping & lowering",items:["Recheck your knot and your partner's belay before you leave the ground.","Watch for back-clips and Z-clips on the first few bolts.","Make sure the rope reaches the anchor, and knot the belay end.","Lower and clean the anchor deliberately; call for 'take' clearly."]},
trad:{title:"Gear & anchors",items:["Build redundant, equalized anchors from independent pieces.","Place protection before the hard moves, not after them.","Manage rope drag; extend placements on wandering pitches.","Know your bail options if the crack thins or blanks out."]},
bouldering:{title:"Spotting & landing",items:["Set pads over uneven ground and the likely fall zone.","A spotter protects your head and spine, they do not catch you.","Down-climb when you can; commit to a clean fall when you cannot.","On highballs, treat the top-out like a solo, a fall is serious."]},
scrambling:{title:"Exposure & route-finding",items:["Know the spots where a slip turns into a long fall.","Most incidents happen off-route on loose ground, so stay on route.","Wet, icy, or sandy rock changes everything, turn back for weather.","On chains and narrow ledges, wait for two-way traffic to clear."]},
hiking:{title:"Navigation & weather",items:["Carry a map or GPS and check the forecast and your daylight.","Turn back for afternoon storms, especially above treeline.","Carry more water than you expect and know reliable sources.","Share your plan and expected return time with someone."]},
alpine:{title:"Snow, weather & timing",items:["Check the avalanche forecast and recent freeze-thaw history.","Start early to beat afternoon warming and thunderstorms.","Set a turnaround time and know your bail routes.","Watch for altitude effects; pace yourself and stay hydrated."]},
mountaineering:{title:"Glacier & high-mountain",items:["Travel roped on glaciers and know crevasse rescue.","Check avalanche danger and overnight snow stability.","Start in the dark for a firm freeze and turn around on time.","Manage altitude, cold, and fast-changing weather."]},
ice:{title:"Ice quality & falling hazard",items:["Test the ice and your screws; avoid sun-rotten or detached daggers.","Falling ice is the main danger, so mind any teams above you.","It climbs best after a good overnight freeze; warm spells are risky.","Belay out of the fall line of ice and dropped tools."]},
mixed:{title:"Mixed & dry-tooling",items:["Falling ice and rock are constant; helmet on and belay off the line.","Verify ice features and fixed gear before you commit.","Conditions swing fast with sun and temperature.","Manage rope drag across the rock-to-ice transitions."]},
aid:{title:"Aid & big-wall",items:["Back up every critical placement and test it before weighting.","Watch for gear failure and zipper falls on marginal pieces.","Manage haul lines and anchor transitions methodically.","Fixed gear varies, so inspect it rather than trusting it blindly."]},
_default:{title:"Safety essentials",items:["Match your protection and pace to the terrain and conditions.","Check the forecast and set a turnaround time before you commit.","Carry the right gear for the discipline and know how to bail.","Tell someone your plan and expected return time."]}
};
const WATCH={sport:["Ground-fall potential on the first 2-3 bolts — stick-clip the first bolt and keep a sharp belay until you are clipped high.","Avoid back-clipping and Z-clipping; check each clip is correct.","Knot the belayer's end and confirm the rope is long enough before lowering — lowering off the end is a common accident.","Use an attentive, ideally assisted-braking belay; the leader's first clip is the most dangerous moment."],trad:["Place protection before the hard moves, not after — and watch for runout sections with no good gear.","Beware marginal, expanding, or behind-loose-block placements; back up the questionable ones.","Manage rope drag — extend wandering placements so a fall does not zipper your gear.","Build redundant, equalized anchors, and know your bail options if the crack blanks out."],bouldering:["Cover the actual fall and top-out zone with pads, and flatten landings over rocks and roots.","A spotter protects your head and spine — they do not catch you.","Downclimb when you can; on highballs treat a fall like a ground-fall."],scrambling:["Know the spots where a slip becomes a long fall — most incidents happen off-route on loose ground.","Test holds; loose rock is common, and do not knock rock onto people below.","Wet, icy, or sandy rock changes everything — back off for weather.","On chains and narrow ledges, wait for two-way traffic to clear."],hiking:["Carry map / GPS, check daylight, and turn back for afternoon storms — especially above treeline.","Plan your water sources and carry more than you expect.","Cross rivers early when flows are low, and unbuckle your pack hip belt before crossing.","Share your plan and expected return time."],alpine:["Rockfall is worst late morning and in the evening as freeze-thaw loosens rock and ice — move early and fast, and do not linger in couloirs.","Avoid lingering under seracs and icefall; they calve without warning.","Watch for afternoon lightning and fast weather changes; set a turnaround time and keep it.","Couloirs funnel falling rock and ice — minimize time in the firing line."],mountaineering:["Travel roped on glaciers and know crevasse rescue — hidden crevasses and weak snow bridges are a lethal threat.","Avoid routes under seracs and minimize time exposed to icefall and rockfall.","Check the avalanche forecast and recent freeze-thaw; start in the dark for a firm freeze.","Manage altitude (acclimatize, watch for AMS) and cornices on summit ridges."],ice:["Falling ice is the main danger — belay out of the fall line and mind any team above you.","Watch for brittle ice and dinner-plating; test your tools and screws.","It climbs best after a good overnight freeze; warm spells and sun make it dangerous.","Beware sun-rotten or detached daggers and free-standing pillars."],mixed:["Falling ice and rock are constant — helmet on and belay off the fall line.","Verify fixed gear and ice features before you commit; conditions swing fast with sun and temperature.","Manage rope drag across the rock-to-ice transitions."],aid:["Back up every critical placement and test it before you fully weight it; watch for zipper and factor-2 falls on marginal gear.","Manage haul lines and anchor transitions methodically, and do not drop gear on the party below.","Inspect fixed gear rather than trusting it blindly."],_default:["Match your protection and pace to the terrain and conditions.","Check the forecast and set a turnaround time before you commit.","Tell someone your plan and expected return time."]};

function EmergencyRescueCard({route,mountain}){return (function(){var st=mountain;var g=0;while(st&&st.areaType!=="state"&&st.parentId&&g<8){st=MOUNTAINS.find(function(x){return x.id===st.parentId;});g++;}var stateName=(st&&st.areaType==="state")?st.name:((mountain&&mountain.region)||"");var cst=mountain;var g2=0;while(cst&&cst.areaType!=="country"&&cst.parentId&&g2<10){cst=MOUNTAINS.find(function(x){return x.id===cst.parentId;});g2++;}var countryName=(cst&&cst.areaType==="country")?cst.name:"United States";var EM_NUM={"United States":["911","dial 911 first — it reaches the county sheriff, who coordinates search and rescue for this area."]};var em=EM_NUM[countryName]||["112","dial 112 — the EU-wide emergency number reaches local police, fire, and ambulance dispatch."];var SARS={Utah:[["Utah County SAR","(801) 794-3970"],["Salt Lake County SAR","(801) 743-7100"],["Grand County SAR (Moab)","(435) 259-8115"],["Washington County (Zion)","(435) 634-5730"]]};var local=SARS[stateName]||null;return <div style={{background:C.card,borderRadius:12,padding:"13px 15px",border:"1px solid "+C.border}}><div style={{fontSize:12,fontWeight:700,color:C.amber,marginBottom:8}}>{"EMERGENCY & RESCUE"+(stateName?" — "+stateName:"")}</div>{(function(){var em=route.emergency||{};var rows=[["Dispatch / ranger",em.sheriffDispatch],["Ranger station",em.rangerStation],["Nearest hospital",em.nearestHospital],["County",em.county]].filter(function(x){return x[1];});if(!rows.length&&!em.notes)return null;return <div>{rows.map(function(x,i){return <div key={"re"+i} style={{display:"flex",justifyContent:"space-between",gap:10,padding:"5px 0",borderBottom:"1px solid "+C.borderLight}}><span style={{fontSize:12,color:C.textSub,flexShrink:0}}>{x[0]}</span><span style={{fontSize:12,color:C.text,fontWeight:600,textAlign:"right"}}>{x[1]}</span></div>;})}{em.notes?<div style={{fontSize:11.5,color:C.textMuted,padding:"5px 0",lineHeight:1.4}}>{em.notes}</div>:null}</div>;})()}<div style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid "+C.borderLight}}><span style={{fontSize:12,color:C.textSub}}>Emergency</span><span style={{fontSize:12,color:C.amber,fontWeight:700}}>{em[0]}</span></div><div style={{fontSize:12,color:C.textSub,lineHeight:1.55,padding:"7px 0 2px"}}>{"In an emergency, "+em[1]}</div>{local?<div><div style={{fontSize:11.5,fontWeight:800,letterSpacing:0.4,color:C.textMuted,margin:"6px 0 3px"}}>NON-EMERGENCY DISPATCH · VERIFY BEFORE YOU RELY ON IT</div>{local.map(function(x){return <div key={x[0]} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid "+C.borderLight}}><span style={{fontSize:12,color:C.textSub}}>{x[0]}</span><span style={{fontSize:12,color:C.amber,fontWeight:600}}>{x[1]}</span></div>;})}</div>:null}<div style={{fontSize:11.5,color:C.textMuted,lineHeight:1.5,paddingTop:7}}>Save the local ranger or sheriff dispatch number before you lose signal — and confirm it against an official county source before you go.</div></div>;})();}
function avyCenterFor(mountain){var st=mountain,g=0;while(st&&st.areaType!=="state"&&st.parentId&&g<8){st=MOUNTAINS.find(function(x){return x.id===st.parentId;});g++;}var stateName=(st&&st.areaType==="state")?st.name:((mountain&&mountain.region)||"");var zone=(mountain&&mountain.avyZone)||"";var host=({Utah:"utahavalanchecenter.org",Washington:"nwac.us",Colorado:"avalanche.state.co.us",California:"sierraavalanchecenter.org"})[stateName]||"avalanche.org";var label=({Utah:"Utah Avalanche Center",Washington:"Northwest Avalanche Center",Colorado:"Colorado Avalanche Information Center",California:"Sierra Avalanche Center"})[stateName]||"avalanche.org";var path=host==="utahavalanchecenter.org"?(zone.indexOf("Uintas")>=0?"/forecast/uintas":zone.indexOf("Salt Lake")>=0?"/forecast/salt-lake":""):"";return [label,host,"https://"+host+path];}
function EditIconButton({onClick,title,size=16}){return <button onClick={onClick} title={title} style={{background:"none",border:"none",color:C.textMuted,cursor:"pointer",padding:"2px 4px",display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:size,lineHeight:1,marginLeft:4,opacity:0.6,transition:"opacity 0.15s"}} onMouseEnter={e=>e.target.style.opacity="1"} onMouseLeave={e=>e.target.style.opacity="0.6"}>✎</button>;}
