    <div className="cm-stagger">{shown.map(({t},i)=><div key={i} onClick={()=>onOpen&&onOpen(t)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 0",borderBottom:i<shown.length-1?`1px solid ${C.borderLight}`:"none",cursor:onOpen?"pointer":"default"}}><div style={{flex:1,minWidth:0}}><div style={{fontSize:13,fontWeight:600}}>{t.route.name}</div><div style={{fontSize:12,color:C.textMuted}}>{t.mtn.name} · {t.route.grade} · {t.date}</div></div><div style={{textAlign:"right",flexShrink:0}}><Pill label={t.tickType} color={C.blue} bg={C.blueBg} sm/><div style={{marginTop:3}}><Stars n={t.stars} size={11}/></div></div>{onOpen?<span style={{color:C.blue,marginLeft:4}}>→</span>:null}</div>)}</div>
