                {pt==="objectives"?<div><SL>Objectives</SL>{climber.objectiveIds.length?<div style={{fontSize:12,color:C.textMuted,marginBottom:9,lineHeight:1.5}}>Tap to plan a crew on any of these — even ones not yet on your list.</div>:<div style={{fontSize:13,color:C.textMuted}}>No objectives listed yet.</div>}{climber.objectiveIds.map(id=>{const r=ROUTES.find(x=>x.id===id);const shared=ME.objectiveIds.includes(id);return r?<div key={id} style={{background:shared?C.blueBg:C.card,borderRadius:10,padding:"10px 12px",marginBottom:7,border:`1px solid ${shared?C.blueDim:C.border}`,display:"flex",alignItems:"center",gap:10}}><div style={{flex:1,minWidth:0}}><div style={{fontWeight:700,fontSize:13.5}}>{r.name}</div><div style={{fontSize:12,color:C.textMuted,marginTop:1}}>{(MOUNTAINS.find(m=>m.id===r.mountainId)||{}).name} · {r.grade}</div>{shared?<div style={{fontSize:12,color:C.blue,marginTop:3}}>You both want this!</div>:null}</div>{onFormCrew?<button onClick={()=>onFormCrew(r)} style={{flexShrink:0,padding:"7px 11px",background:shared?C.blue:C.blueBg,color:shared?"#fff":C.blue,border:shared?"none":"1px solid "+C.blueDim,borderRadius:9,fontSize:12.5,fontWeight:700,cursor:"pointer",whiteSpace:"nowrap"}}>{shared?"Plan together":"Suggest crew"}</button>:null}</div>:null;})}</div>:null}
