function hasVulgarity(str){const t=(str||"").toLowerCase().replace(/[^a-z0-9]/g,"");return !!t&&BADWORDS.some(w=>t.indexOf(w)>=0);}
function LegalView({kind,onBack}){
  const TERMS=[["Acceptance","By creating an account or using ClimbMatch you agree to these Terms. If you do not agree, do not use the app."],["Who can use ClimbMatch","You must be at least 13 to create an account, and 18 or older to book a guide or be verified for belay catches. Accounts for children under 13 are not permitted."],["Your account","Keep your login secure and your profile information accurate — you are responsible for activity on your account, and it is one person per account."],["Community content","Route info, conditions, reviews, and photos you post may be shown to other climbers. You keep ownership of your content and grant ClimbMatch a license to display it in the app. Do not post anything false, harassing, or unlawful."],["Climbing is dangerous — assumption of risk","Climbing, mountaineering, and related activities carry inherent risks of serious injury or death. ClimbMatch provides information and introductions, not professional advice or supervision. You are solely responsible for your own decisions, conditions assessment, and safety. Community route data, grades, and conditions may be wrong or out of date — always verify in the field."],["Partners and belay verification","Belay catches, vouches, and trust scores are community-reported signals, not guarantees of anyone’s skill or reliability. Meet new partners carefully and use your own judgment."],["Guides and bookings","Guides are independent professionals, not employees of ClimbMatch. We verify credentials on a best-effort basis but do not guarantee any guide’s qualifications, insurance, or conduct. Any guided activity is between you and the guide; ClimbMatch is not a party to that contract and is not liable for it."],["Prohibited conduct","No harassment, impersonation, fake reviews, scraping, or attempts to defeat safety or verification features. We may suspend or remove accounts that break these rules."],["Disclaimers and liability","The app is provided “as is.” To the maximum extent allowed by law, ClimbMatch is not liable for injuries, losses, or damages arising from use of the app, reliance on its data, partner introductions, or guided trips."],["Termination","You can delete your account at any time in Settings. We may suspend accounts that violate these Terms or create safety risks."],["Changes","We may update these Terms and will notify you of material changes. Continued use means you accept the updated Terms."],["Contact","Questions about these Terms: legal@climbmatch.example."]];
  const PRIVACY=[["What we collect","Account details (name, email, username), profile info (disciplines, grades, gear, photos, bio), climbing logs, optional emergency contacts, approximate or precise location when you enable it, and basic device and usage data."],["How we use it","To match you with partners and objectives, power safety and trust features, surface relevant climbs and conditions, and communicate with you. We do not sell your personal information."],["What others can see","Other climbers see your public profile as governed by your privacy settings — your username or real name, and the fields you choose to make visible. Emergency contacts are never shown on your public profile."],["Location","You control location sharing. “Approximate location only” shares your city rather than your exact spot. Precise location, when enabled, powers nearby routes, weather, and — if you opt in — float plans and search-and-rescue."],["Sharing with others","We share data with service providers who help run the app (hosting, maps, payments) under contract, and when required by law. We never sell your data."],["Your rights","You can access, correct, export, or delete your data, and opt out of non-essential processing. Account deletion is available in Settings and removes your profile and personal data, subject to limited legal retention."],["Data retention","We keep your data while your account is active and for a limited period afterward as needed for legal, safety, and dispute purposes, then delete or anonymize it."],["Security","We protect your data with encryption in transit and at rest and limit internal access. No system is perfectly secure, so use a strong, unique password or a passkey."],["Children","ClimbMatch is not directed to children under 13, and we do not knowingly collect their data. If you believe a child has provided data, contact us and we will delete it."],["Changes","We may update this Policy and will note the effective date; material changes will be highlighted in the app."],["Contact","Privacy questions or data requests: privacy@climbmatch.example."]];
  const isP=kind==="privacy";const doc=isP?PRIVACY:TERMS;const title=isP?"Privacy Policy":"Terms of Service";
  return <div style={{fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",background:C.bg,minHeight:"100vh",color:C.text,maxWidth:520,margin:"0 auto"}}>
    <div style={{position:"sticky",top:0,background:C.surface,borderBottom:"1px solid "+C.border,padding:"12px 16px",display:"flex",alignItems:"center",gap:10,zIndex:5}}><button onClick={onBack} style={{background:"none",border:"none",color:C.blue,fontSize:15,fontWeight:600,cursor:"pointer",padding:0}}>← Back</button><span style={{fontSize:16,fontWeight:700}}>{title}</span></div>
    <div style={{padding:"16px 18px 40px"}}><div style={{fontSize:11.5,color:C.textMuted,lineHeight:1.5,marginBottom:16,background:C.surface,border:"1px solid "+C.border,borderRadius:10,padding:"10px 12px"}}>Plain-language template for the ClimbMatch prototype. Before launch, have a lawyer review it and tailor it to the data you actually collect and the regions you operate in. Last updated June 2026.</div>{doc.map((sec,i)=><div key={i} style={{marginBottom:16}}><div style={{fontSize:14,fontWeight:700,marginBottom:5}}>{(i+1)+". "+sec[0]}</div><div style={{fontSize:13,color:C.textSub,lineHeight:1.6}}>{sec[1]}</div></div>)}</div>
  </div>;
}
