function sunTimes(lat,date){try{const d=new Date(date+"T12:00:00");const start=new Date(d.getFullYear(),0,0);const doy=Math.floor((d-start)/86400000);const decl=23.44*Math.PI/180*Math.sin(2*Math.PI*(doy-81)/365);const latR=lat*Math.PI/180;let cosH=-Math.tan(latR)*Math.tan(decl);if(cosH>1)return{daylight:0,sunrise:null,sunset:null};if(cosH<-1)return{daylight:24,sunrise:null,sunset:null};const H=Math.acos(cosH)*180/Math.PI;const dl=2*H/15;return{daylight:dl,sunrise:12-dl/2,sunset:12+dl/2};}catch(e){return null;}}
