function analyzeAlignment(members){
  const flags=[];const risks=members.map(m=>m.riskTolerance).filter(Boolean);
  if(risks.includes("conservative")&&risks.includes("aggressive"))flags.push({severity:"critical",category:"Risk Tolerance",msg:"Conservative and Aggressive members in same party. Explicit conversation required before confirming.",icon:""});
  members.forEach(m=>{if(!m.preClimbAnswers)return;const a=m.preClimbAnswers;if(a.physical>=2)flags.push({severity:"warning",category:"Fitness",msg:`${m.name} flagged fitness concerns. Discuss pacing.`,icon:""});if(a.gear>=2)flags.push({severity:"warning",category:"Gear",msg:`${m.name} has gear gaps. Resolve before departure.`,icon:""});if(a.turnaround>=2)flags.push({severity:"critical",category:"Safety",msg:`${m.name} indicated flexibility on turnaround time. Requires explicit group agreement.`,icon:""});if(a.communication>=2)flags.push({severity:"info",category:"Team",msg:`${m.name} finds it hard to voice concerns. Proactively check in.`,icon:""});if(a.experience>=2)flags.push({severity:"warning",category:"Experience",msg:`${m.name} flagged experience concerns. Plan clear guidance.`,icon:""});});
  const pending=members.filter(m=>!m.preClimbAnswers);
  if(pending.length)flags.push({severity:"info",category:"Pending",msg:`${pending.map(m=>m.name).join(", ")} ${pending.length===1?"has":"have"} not completed the questionnaire.`,icon:""});
  const allDone=members.every(m=>m.preClimbAnswers);const crit=flags.filter(f=>f.severity==="critical").length,warn=flags.filter(f=>f.severity==="warning").length;
  return{flags,ready:allDone&&crit===0&&warn===0,discussion:allDone&&(crit>0||warn>0),allDone,crit,warn};
}
