function inArea(mid,sid){if(!sid)return true;let m=MOUNTAINS.find(x=>x.id===mid),_g=0;while(m&&_g++<64){if(m.id===sid)return true;m=m.parentId?MOUNTAINS.find(x=>x.id===m.parentId):null;}return false;}
function _lev(a,b){const m=a.length,n=b.length;if(!m)return n;if(!n)return m;let prev=Array.from({length:n+1},(_,i)=>i),cur=new Array(n+1);for(let i=1;i<=m;i++){cur[0]=i;for(let j=1;j<=n;j++){const cost=a[i-1]===b[j-1]?0:1;cur[j]=Math.min(prev[j]+1,cur[j-1]+1,prev[j-1]+cost);}const t=prev;prev=cur;cur=t;}return prev[n];}
function _tol(w){return w.length<=4?1:w.length<=7?2:3;}
function _norm(s){return (s||"").toLowerCase().replace(/\bmtn\b\.?/g,"mountain").replace(/\bmt\b\.?/g,"mount").replace(/\bst\b\.?/g,"saint").replace(/\bpk\b\.?/g,"peak");}
function fuzzyMatch(q,text){q=_norm(q).trim();if(!q)return true;text=_norm(text);if(text.includes(q))return true;const tw=text.split(/[^a-z0-9]+/).filter(Boolean),qw=q.split(/[^a-z0-9]+/).filter(Boolean);if(!qw.length||!tw.length)return false;return qw.every(qq=>tw.some(w=>w.startsWith(qq)||qq.startsWith(w)||_lev(qq,w)<=_tol(qq)));}
